import { Box, Button, Container, Typography, Stack } from '@mui/material';

const Hero = () => {
    return (
        <Box
            sx={{
                position: 'relative',
                height: '80vh',
                width: '100%',
                display: 'flex',
                alignItems: 'center',
                overflow: 'hidden',
                borderRadius: { xs: 0, md: '40px' },
                mb: 8,
                background: `linear-gradient(to right, rgba(15, 17, 21, 0.9) 20%, rgba(15, 17, 21, 0.2) 60%), url('/hero.png')`,
                backgroundSize: 'cover',
                backgroundPosition: 'center',
            }}
        >
            <Container maxWidth="lg">
                <Box sx={{ maxWidth: '600px', color: 'white' }}>
                    <Typography
                        variant="h1"
                        sx={{
                            fontSize: { xs: '3rem', md: '4.5rem' },
                            mb: 2,
                            lineHeight: 1.1,
                            textTransform: 'uppercase',
                        }}
                    >
                        Define Your <br />
                        <Box component="span" sx={{ color: 'primary.main' }}>Performance</Box>
                    </Typography>
                    <Typography
                        variant="body1"
                        sx={{
                            fontSize: '1.2rem',
                            mb: 4,
                            color: 'text.secondary',
                            maxWidth: '450px',
                        }}
                    >
                        Experience the perfect blend of luxury minimalism and high-performance engineering. Crafted for those who demand excellence in every move.
                    </Typography>
                    <Stack direction="row" spacing={2}>
                        <Button
                            variant="contained"
                            size="large"
                            sx={{
                                height: '56px',
                                px: 4,
                                fontSize: '1rem',
                            }}
                        >
                            Shop Collection
                        </Button>
                        <Button
                            variant="outlined"
                            size="large"
                            sx={{
                                height: '56px',
                                px: 4,
                                fontSize: '1rem',
                                color: 'white',
                                borderColor: 'rgba(255,255,255,0.3)',
                            }}
                        >
                            Our Story
                        </Button>
                    </Stack>
                </Box>
            </Container>
        </Box>
    );
};

export default Hero;
